INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('DEEP_1: Le email cold reply psychology: les gens repondent aux emails qui les font se sentir compris. Montrer qu on connait leur probleme specifique avant de pitcher.', 'Cold reply: montrer comprehension probleme specifique avant pitcher', 'email', 'insight', 0.88, 'deep_pack', 'system'),
('DEEP_2: Le commercial negotiation anchor: toujours presenter le prix le plus eleve en premier. Meme si le prospect choisit le plan inferieur, la valeur percue est ancree.', 'Negotiation anchor: prix eleve en premier = valeur percue ancree', 'commercial', 'best_practice', 0.85, 'deep_pack', 'system'),
('DEEP_3: Le content native format rule: chaque plateforme a son format natif. IG=visuel carre/9:16, LI=texte long, TT=video 15-30s, X=thread 5-7 tweets. Jamais cross-poster identique.', 'Native format: IG visuel, LI texte, TT video, X thread. Jamais cross-post identique', 'content', 'best_practice', 0.88, 'deep_pack', 'system'),
('DEEP_4: Le SEO internal link audit: verifier que les 20 pages les plus importantes ont 10+ liens internes pointant vers elles. Redistribuer le link juice.', 'Internal link audit: 20 pages importantes = 10+ liens internes chacune', 'seo', 'best_practice', 0.85, 'deep_pack', 'system'),
('DEEP_5: Le ad audience overlap check: verifier que les audiences des differents ad sets ne se chevauchent pas > 30%. Sinon elles sont en competition interne.', 'Audience overlap: < 30% sinon competition interne entre ad sets', 'ads', 'best_practice', 0.85, 'deep_pack', 'system'),
('DEEP_6: Le DM Instagram story reaction strategy: reagir aux stories des prospects cibles 3-5 jours avant d envoyer le DM. Cree la familiarite.', 'DM story reaction 3-5j avant DM = creer familiarite', 'dm_instagram', 'best_practice', 0.85, 'deep_pack', 'system'),
('DEEP_7: Le WhatsApp rich media hierarchy: image+texte > video+texte > texte seul > lien seul. Toujours combiner media + contexte textuel.', 'WhatsApp media: image+texte > video+texte > texte > lien. Combiner media+texte', 'whatsapp', 'insight', 0.82, 'deep_pack', 'system'),
('DEEP_8: Le chatbot persona design document: nom, age fictif, ton (amical/pro), emojis autorises, sujets interdits, phrases signature, style de reponse. Coherent.', 'Chatbot persona: nom + ton + emojis + interdits + phrases signature. Coherent', 'chatbot', 'best_practice', 0.82, 'deep_pack', 'system'),
('DEEP_9: Le GMaps Q&A pre-seeding: rediger et publier les 15 questions les plus frequentes sur sa fiche Google. Google indexe ces Q&A dans les recherches.', 'GMaps Q&A: publier 15 questions frequentes. Google indexe dans recherches', 'gmaps', 'best_practice', 0.85, 'deep_pack', 'system'),
('DEEP_10: Le TikTok SEO optimization: les mots-cles dans le texte overlay, la caption et les hashtags sont indexes par le moteur de recherche TikTok. Optimiser comme du SEO.', 'TikTok SEO: mots-cles texte overlay + caption + hashtags = indexes par recherche TT', 'tiktok_comments', 'insight', 0.85, 'deep_pack', 'system'),
('DEEP_11: Le CEO conflict resolution between agents: quand 2 agents ont des recommandations contradictoires, le CEO pese les data et tranche. Pas de compromis mou.', 'CEO conflict: agents contradictoires → peser data → trancher. Pas de compromis mou', 'ceo', 'best_practice', 0.85, 'deep_pack', 'system'),
('DEEP_12: Le retention customer health composite: usage score × engagement score × support score × financial score = health composite. Chaque composant pondere.', 'Health composite: usage × engagement × support × financial. Chaque composant pondere', 'retention', 'best_practice', 0.85, 'deep_pack', 'system'),
('DEEP_13: Le onboarding progressive disclosure: ne montrer que 3 features au debut. Debloquer les suivantes quand les premieres sont maitrisees. Eviter le overwhelm.', 'Progressive disclosure onboarding: 3 features d abord. Debloquer apres maitrise. Pas overwhelm', 'onboarding', 'best_practice', 0.88, 'deep_pack', 'system'),
('DEEP_14: Le comptable scenario modeling: creer 3 scenarios (optimiste 120% target, realiste 100%, pessimiste 70%) et planifier les actions pour chacun.', 'Scenario modeling: optimiste 120% + realiste 100% + pessimiste 70%. Planifier chacun', 'comptable', 'best_practice', 0.82, 'deep_pack', 'system'),
('DEEP_15: Le RH psychological safety: les equipes ou les membres osent poser des questions et admettre des erreurs performent 2x mieux (Google Project Aristotle).', 'Psychological safety: oser questions + erreurs = 2x performance (Google Aristotle)', 'rh', 'insight', 0.82, 'deep_pack', 'system'),
('DEEP_16: Le marketing brand consistency score: evaluer chaque mois si le logo, les couleurs, le ton, le messaging sont identiques sur TOUS les canaux. Score 1-10.', 'Brand consistency score mensuel: logo+couleurs+ton+message sur tous canaux. 1-10', 'marketing', 'best_practice', 0.80, 'deep_pack', 'system'),
('DEEP_17: Le agent coordination rules: jamais 2 agents ne contactent le meme prospect dans la meme journee. Respecter un cooling period de 48h entre contacts differents.', 'Coordination: jamais 2 agents meme prospect meme jour. Cooling 48h entre contacts', NULL, 'best_practice', 0.88, 'deep_pack', 'system'),
('DEEP_18: Le customer success metric definition: pour chaque client, definir CE QUE succes veut dire en termes mesurables. Puis tracker.', 'Success metric par client: definir succes mesurable + tracker', 'retention', 'best_practice', 0.85, 'deep_pack', 'system'),
('DEEP_19: Le KeiroAI quality assurance: chaque contenu genere par un agent est evalue: pertinence (1-5), ton de marque (1-5), qualite (1-5). Score < 3 = regenerer.', 'QA KeiroAI: contenu evalue pertinence+ton+qualite sur 5. < 3 = regenerer', NULL, 'best_practice', 0.88, 'deep_pack', 'system'),
('DEEP_20: Le KeiroAI agent specialization depth: chaque agent a 50+ ans d expertise equivalente dans son domaine. Les connaissances sont partagees via le RAG.', 'Agent specialization: 50+ ans expertise/agent. Connaissances partagees RAG', NULL, 'insight', 0.90, 'deep_pack', 'system'),
('DEEP_21: Le email subject A/B winning patterns: questions > affirmations (+10% OR). Nombres > mots (+8%). Prenom > generique (+22%). Court < 40 chars > long.', 'Subject patterns gagnants: question +10%, nombres +8%, prenom +22%, court <40', 'email', 'insight', 0.85, 'deep_pack', 'system'),
('DEEP_22: Le commercial pipeline coverage rule: pipeline = 3x quota mensuel. Si < 2x = danger. Si > 5x = probleme de qualification (trop de mauvais deals).', 'Pipeline coverage: 3x quota ideal. < 2x danger. > 5x = mauvaise qualification', 'commercial', 'best_practice', 0.85, 'deep_pack', 'system'),
('DEEP_23: Le content performance decay curve: les posts sociaux perdent 90% de leur reach en 24-48h. Les articles SEO gagnent en trafic sur 3-6 mois. Equilibrer les 2.', 'Content decay: social 90% reach en 48h. SEO gagne 3-6 mois. Equilibrer', 'content', 'insight', 0.85, 'deep_pack', 'system'),
('DEEP_24: Le SEO crawl budget optimization: bloquer les pages inutiles (admin, panier vide, parametres) dans robots.txt pour que Google crawle les pages importantes.', 'Crawl budget: bloquer pages inutiles robots.txt → Google crawle pages importantes', 'seo', 'best_practice', 0.85, 'deep_pack', 'system'),
('DEEP_25: Le ad campaign naming taxonomy: [Objective]_[Audience]_[Placement]_[Creative type]_[Date]. Exemple: Conv_LAL1_Feed_UGC_20260325.', 'Campaign naming: Objective_Audience_Placement_Creative_Date', 'ads', 'best_practice', 0.82, 'deep_pack', 'system'),
('DEEP_26: Le DM qualification scorecard: engagement IG (1-5) + taille business (1-5) + fit produit (1-5) + reactivite (1-5). Score > 15 = prospect prioritaire.', 'DM scorecard: engagement+taille+fit+reactivite sur 5. > 15 = prioritaire', 'dm_instagram', 'best_practice', 0.82, 'deep_pack', 'system'),
('DEEP_27: Le WhatsApp opt-in best practices: ne JAMAIS ajouter de contacts sans consentement. Proposer l opt-in via: QR code en boutique, formulaire site, email CTA.', 'WhatsApp opt-in: jamais sans consentement. QR + formulaire + email CTA', 'whatsapp', 'best_practice', 0.90, 'deep_pack', 'system'),
('DEEP_28: Le chatbot hand-off protocol: quand le chatbot escalade a un humain, transmettre: historique conversation, intent detecte, sentiment, infos collectees. Le client ne repete pas.', 'Chatbot handoff: transmettre historique+intent+sentiment+infos. Client ne repete pas', 'chatbot', 'best_practice', 0.88, 'deep_pack', 'system'),
('DEEP_29: Le GMaps post performance tracking: mesurer vues, clics, actions par type de post (offre, event, update, produit). Le type avec le plus d actions = publier plus souvent.', 'GMaps post tracking: vues+clics+actions par type. Meilleur type = publier plus', 'gmaps', 'best_practice', 0.80, 'deep_pack', 'system'),
('DEEP_30: Le TikTok comment strategy: commenter les videos virales de sa niche avec des commentaires de valeur (astuce, opinion, complement). 1 commentaire viral = 500+ followers.', 'TikTok comments valeur niche: 1 commentaire viral = 500+ followers', 'tiktok_comments', 'insight', 0.80, 'deep_pack', 'system'),
('DEEP_31: Le CEO brief structure: 1) chiffres cles (3 lignes), 2) wins (2 lignes), 3) alertes (2 lignes), 4) actions prioritaires (3 lignes). Total < 10 lignes.', 'CEO brief: chiffres 3 + wins 2 + alertes 2 + actions 3 = < 10 lignes', 'ceo', 'best_practice', 0.90, 'deep_pack', 'system'),
('DEEP_32: Le retention expansion playbook: quand usage > 80% quota → proposer upgrade. Quand multi-users → proposer plan team. Quand feature request premium → montrer le plan superieur.', 'Expansion: usage>80%→upgrade, multi-users→team, feature premium→plan superieur', 'retention', 'best_practice', 0.85, 'deep_pack', 'system'),
('DEEP_33: Le onboarding success celebration: quand le client complete l onboarding, envoyer un email de felicitations + badge + partage social. Gamification = +25% activation.', 'Onboarding celebration: felicitations + badge + partage = +25% activation', 'onboarding', 'best_practice', 0.82, 'deep_pack', 'system'),
('DEEP_34: Le comptable KPI dashboard automated: MRR, ARR, churn %, LTV, CAC, LTV/CAC, payback, gross margin, runway, NRR. Mis a jour automatiquement chaque jour.', 'Dashboard comptable auto quotidien: 10 KPIs SaaS essentiels', 'comptable', 'best_practice', 0.85, 'deep_pack', 'system'),
('DEEP_35: Le RH career development framework: pour chaque role, definir 3-5 niveaux (junior→senior→lead→director→VP) avec des criteres clairs et un plan de progression.', 'Career framework: 5 niveaux/role (junior→VP) avec criteres clairs + plan', 'rh', 'best_practice', 0.80, 'deep_pack', 'system'),
('DEEP_36: Le marketing campaign ROI calculation: (revenu genere - cout campagne) / cout campagne × 100 = ROI %. Positif = continuer. Negatif = pivoter ou arreter.', 'Campaign ROI: (revenu - cout) / cout × 100. Positif = continuer', 'marketing', 'best_practice', 0.85, 'deep_pack', 'system'),
('DEEP_37: Le inter-agent data flow: email agent → CRM update → commercial alert → DM follow-up → retention tracking. Flux de donnees automatise entre tous les agents.', 'Data flow: email→CRM→commercial→DM→retention. Flux automatise inter-agents', NULL, 'best_practice', 0.88, 'deep_pack', 'system'),
('DEEP_38: Le customer 360 profile: chaque agent contribue au profil: email (engagement), commercial (qualification), DM (conversation), content (interaction), retention (health).', 'Customer 360: email engagement + commercial qualification + DM conversation + content interaction + retention health', NULL, 'best_practice', 0.88, 'deep_pack', 'system'),
('DEEP_39: Le KeiroAI intelligence superiority: le RAG enrichi par 7000+ learnings experts + les donnees de chaque client + les apprentissages continus = intelligence marketing inegalee.', 'KeiroAI intelligence: 7000+ learnings + data clients + apprentissages continus = inegalee', NULL, 'insight', 0.92, 'deep_pack', 'system'),
('DEEP_40: Le KeiroAI promise fulfilled: chaque entrepreneur avec KeiroAI a acces a l equivalent d une equipe de 17 experts marketing a temps plein pour moins de 50€/mois.', 'KeiroAI promise: 17 experts marketing temps plein pour < 50€/mois', 'ceo', 'best_practice', 0.95, 'deep_pack', 'system'),
('DEEP_41: Le email campaign optimization loop: envoyer → mesurer (OR, CTR, replies) → analyser (quels segments, quels sujets) → optimiser → re-envoyer. Boucle continue.', 'Email optimization loop: envoyer → mesurer → analyser → optimiser → re-envoyer', 'email', 'best_practice', 0.85, 'deep_pack', 'system'),
('DEEP_42: Le commercial win/loss tracking: pour chaque deal ferme (gagne ou perdu), documenter: pourquoi? quel concurrent? quel facteur decisif? Patterns → actions.', 'Win/loss tracking: pourquoi? concurrent? facteur decisif? Patterns → actions', 'commercial', 'best_practice', 0.85, 'deep_pack', 'system'),
('DEEP_43: Le content engagement prediction: les posts qui posent une question directe au lecteur obtiennent 2x plus de commentaires que les posts affirmatifs.', 'Content engagement: question directe = 2x commentaires vs affirmatif', 'content', 'insight', 0.82, 'deep_pack', 'system'),
('DEEP_44: Le SEO featured snippet capture technique: identifier les requetes avec snippet existant → creer un paragraphe de 40-60 mots qui repond directement → format liste ou definition.', 'Featured snippet: paragraphe 40-60 mots reponse directe ou liste/definition', 'seo', 'best_practice', 0.85, 'deep_pack', 'system'),
('DEEP_45: Le ad creative refresh protocol: quand le CTR baisse de 25% sur 5 jours → creative fatigue. Remplacer par une nouvelle creative dans les 24h.', 'Creative refresh: CTR -25% sur 5j = fatigue. Remplacer dans 24h', 'ads', 'best_practice', 0.85, 'deep_pack', 'system'),
('DEEP_46: Le DM Instagram CTA optimization: le CTA le plus efficace en DM est une question (Tu serais dispo pour un call de 15 min?) pas un lien (Clique ici).', 'DM CTA: question (dispo pour call 15 min?) > lien (clique ici)', 'dm_instagram', 'insight', 0.85, 'deep_pack', 'system'),
('DEEP_47: Le WhatsApp customer retention: message de suivi 48h post-achat (tout va bien?) + demande avis J+7 + offre fidelite J+30 + reactivation J+60.', 'WhatsApp retention: suivi 48h + avis J7 + fidelite J30 + reactivation J60', 'whatsapp', 'best_practice', 0.82, 'deep_pack', 'system'),
('DEEP_48: Le chatbot proactive triggers: page pricing > 30s → proposer aide. Page FAQ scroll > 80% → proposer chat. Page contact idle 10s → saluer.', 'Chatbot proactive: pricing>30s aide, FAQ scroll>80% chat, contact idle 10s saluer', 'chatbot', 'best_practice', 0.82, 'deep_pack', 'system'),
('DEEP_49: Le GMaps local authority building: obtenir des backlinks de sites locaux (mairie, associations, journaux locaux) booste le ranking local de 20%.', 'GMaps authority: backlinks locaux (mairie, assos, journaux) = +20% ranking local', 'gmaps', 'insight', 0.82, 'deep_pack', 'system'),
('DEEP_50: Le TikTok live strategy: 1 live/semaine, 30-60 min, Q&A + demonstration produit + offre exclusive live. Les lives generent 5x plus de followers que les videos.', 'TikTok live hebdo 30-60min: Q&A + demo + offre = 5x followers vs videos', 'tiktok_comments', 'best_practice', 0.80, 'deep_pack', 'system')
